tailwind.config = {
      theme: {
        extend: {
          fontFamily: {
            sans: ['Inter', 'sans-serif'],
            display: ['Sora', 'sans-serif']
          }
        }
      }
    };

(function() {
      const manifestData = '{"name":"my goals","short_name":"my goals","description":"Track your saving goals with daily progress and countdown.","start_url":"./index.html","display":"standalone","orientation":"portrait","background_color":"#060912","theme_color":"#060912","icons":[{"src":"data:image/png;base64,","sizes":"192x192","type":"image/png","purpose":"any maskable"},{"src":"data:image/png;base64,","sizes":"512x512","type":"image/png","purpose":"any maskable"}],"categories":["finance","productivity"]}';
      const blob = new Blob([manifestData], {type: 'application/json'});
      const url = URL.createObjectURL(blob);
      const link = document.createElement('link');
      link.rel = 'manifest';
      link.href = url;
      document.head.appendChild(link);
    })();

if ('serviceWorker' in navigator) {
      const swCode = "const CACHE_NAME = 'mygoals-v1';\nself.addEventListener('install', e => { self.skipWaiting(); });\nself.addEventListener('activate', e => { self.clients.claim(); });\nself.addEventListener('fetch', e => {\n  e.respondWith(\n    caches.match(e.request).then(cached => cached || fetch(e.request).catch(() => cached))\n  );\n});";
      const blob = new Blob([swCode], {type: 'application/javascript'});
      const swUrl = URL.createObjectURL(blob);
      navigator.serviceWorker.register(swUrl);
    }

if ('serviceWorker' in navigator) {
      window.addEventListener('load', () => {
        navigator.serviceWorker.register('./sw.js').catch(() => {});
      });
    }

    const STORE_KEY = 'savingGoals_v1';
    const ACHIEVEMENT_KEY = 'savingGoals_achievements_v1';
    const HISTORY_KEY = 'savingGoals_history_v1';
    const GAME_KEY = 'savingGoals_game_v1';
    const THEME_KEY = 'vaultt_theme';
    const MAX_SAVING_DAYS = 3650;
    const XP_SAVE = 10;
    const XP_COMPLETE = 100;
    const XP_STREAK = 5;
    const WEEKDAY_SHORT = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const BADGE_DEFS = [
      { id: 'first-save', name: 'First Save', icon: 'badge-check' },
      { id: 'seven-day-streak', name: '7-Day Streak', icon: 'flame' },
      { id: 'goal-completed', name: 'Goal Completed', icon: 'trophy' },
      { id: 'consistency-master', name: 'Consistency Master', icon: 'medal' }
    ];

    let deferredPrompt = null;
    let goals = loadGoals();
    let achievements = loadAchievements();
    let savingHistory = loadSavingHistory();
    let gameState = loadGameState();
    let pendingLevelUp = false;
    let recentBadgeId = null;
    let deleteTargetId = null;
    let achievementDeleteTargetId = null;
    let currentImgData = null;
    let toastTimer;
    let calcMode = 'byDays';

    const html = document.documentElement;
    const themeBtn = document.getElementById('themeToggle');
    const installBanner = document.getElementById('installBanner');
    const installBtn = document.getElementById('installBtn');
    const dismissBanner = document.getElementById('dismissBanner');
    const iosBanner = document.getElementById('iosBanner');
    const dismissIosBanner = document.getElementById('dismissIosBanner');

    function refreshIcons() {
      if (window.lucide) {
        window.lucide.createIcons({
          attrs: {
            'stroke-width': 2.2,
            'aria-hidden': 'true'
          }
        });
      }
    }

    function uid() {
      return Date.now().toString(36) + Math.random().toString(36).slice(2, 7);
    }

    function todayISO() {
      const date = new Date();
      date.setMinutes(date.getMinutes() - date.getTimezoneOffset());
      return date.toISOString().slice(0, 10);
    }

    function toISODate(date) {
      const next = new Date(date);
      next.setMinutes(next.getMinutes() - next.getTimezoneOffset());
      return next.toISOString().slice(0, 10);
    }

    function dateFromISO(value) {
      const date = value ? new Date(`${value}T00:00:00`) : new Date();
      date.setHours(0, 0, 0, 0);
      return date;
    }

    function addDays(date, days) {
      const next = new Date(date);
      next.setDate(next.getDate() + days);
      return next;
    }

    function calculateCalendarDaysNeeded(requiredSavingDays, skippedWeekdays = [], startDate = todayISO()) {
      const required = Math.ceil(Number(requiredSavingDays) || 0);
      const skipped = new Set((skippedWeekdays || []).map(Number));

      if (required <= 0) return 0;
      if (skipped.size >= 7) return Infinity;

      const cursor = dateFromISO(startDate);
      let savingDays = 0;
      let calendarDays = 0;
      const maxLoops = required * 10 + 400;

      while (savingDays < required && calendarDays < maxLoops) {
        if (!skipped.has(cursor.getDay())) {
          savingDays++;
        }

        calendarDays++;
        cursor.setDate(cursor.getDate() + 1);
      }

      return savingDays >= required ? calendarDays : Infinity;
    }

    function normalizeSkippedWeekdays(value) {
      if (!Array.isArray(value)) return [];
      return [...new Set(value.map(Number).filter(day => day >= 0 && day <= 6))].sort((a, b) => a - b);
    }

    function normalizeGoal(goal) {
      const target = Math.max(1, Number(goal.target) || 1);
      const days = Math.min(MAX_SAVING_DAYS, Math.max(1, parseInt(goal.days, 10) || 1));
      const fallbackDaily = target / days;
      const dailyAmount = Math.max(0.01, Number(goal.dailyAmount) || fallbackDaily);
      const doneDays = Array.isArray(goal.doneDays)
        ? goal.doneDays.map(Number).filter(day => day >= 1 && day <= days)
        : [];

      return {
        id: goal.id || uid(),
        name: String(goal.name || 'Untitled goal'),
        target,
        days,
        dailyAmount,
        calcMode: goal.calcMode === 'byDaily' ? 'byDaily' : 'byDays',
        skippedWeekdays: normalizeSkippedWeekdays(goal.skippedWeekdays),
        image: goal.image || null,
        startDate: goal.startDate || null,
        doneDays: [...new Set(doneDays)].sort((a, b) => a - b),
        createdAt: goal.createdAt || Date.now(),
        completedAt: goal.completedAt || null
      };
    }

    function normalizeAchievement(achievement) {
      if (!achievement || typeof achievement !== 'object') return null;

      const goal = normalizeGoal(achievement);
      const totalSaved = Math.min(goal.target, Number(achievement.totalSaved) || calcSaved(goal) || goal.target);
      const daysUsed = Math.max(1, Number(achievement.daysUsed) || goal.doneDays.length || goal.days);

      return {
        ...goal,
        completed: true,
        completedAt: achievement.completedAt || goal.completedAt || new Date().toISOString(),
        daysUsed,
        totalSaved
      };
    }

    function buildAchievement(goal) {
      const completedAt = goal.completedAt || new Date().toISOString();
      return normalizeAchievement({
        ...goal,
        completed: true,
        completedAt,
        daysUsed: goal.doneDays.length || goal.days,
        totalSaved: calcSaved(goal)
      });
    }

    function loadGoals() {
      try {
        const data = JSON.parse(localStorage.getItem(STORE_KEY)) || [];
        return Array.isArray(data) ? data.map(normalizeGoal) : [];
      } catch {
        return [];
      }
    }

    function saveGoals(nextGoals) {
      localStorage.setItem(STORE_KEY, JSON.stringify(nextGoals));
    }

    function loadAchievements() {
      try {
        const data = JSON.parse(localStorage.getItem(ACHIEVEMENT_KEY)) || [];
        if (!Array.isArray(data)) return [];

        const seen = new Set();
        return data
          .map(normalizeAchievement)
          .filter(Boolean)
          .filter(item => {
            if (seen.has(item.id)) return false;
            seen.add(item.id);
            return true;
          });
      } catch { return []; }
    }

    function saveAchievements() {
      const seen = new Set();
      achievements = achievements
        .map(normalizeAchievement)
        .filter(Boolean)
        .filter(item => {
          if (seen.has(item.id)) return false;
          seen.add(item.id);
          return true;
        })
        .sort((a, b) => new Date(a.completedAt) - new Date(b.completedAt));
      localStorage.setItem(ACHIEVEMENT_KEY, JSON.stringify(achievements));
    }

    function getLevelFromXP(xp) {
      return Math.floor(Math.max(0, Number(xp) || 0) / 100);
    }

    function normalizeGameState(state = {}) {
      const badgeIds = new Set(BADGE_DEFS.map(badge => badge.id));
      const xp = Math.max(0, Math.floor(Number(state.xp) || 0));
      const badges = Array.isArray(state.badges)
        ? [...new Set(state.badges.filter(id => badgeIds.has(id)))]
        : [];

      return {
        xp,
        level: getLevelFromXP(xp),
        badges,
        streak: Math.max(0, Math.floor(Number(state.streak) || 0)),
        totalSaves: Math.max(0, Math.floor(Number(state.totalSaves) || 0)),
        lastSaveDate: typeof state.lastSaveDate === 'string' ? state.lastSaveDate : null
      };
    }

    function loadGameState() {
      try {
        return normalizeGameState(JSON.parse(localStorage.getItem(GAME_KEY)) || {});
      } catch {
        return normalizeGameState();
      }
    }

    function saveGameState() {
      gameState = normalizeGameState(gameState);
      localStorage.setItem(GAME_KEY, JSON.stringify(gameState));
    }

    function normalizeHistoryEntry(entry) {
      if (!entry || typeof entry !== 'object') return null;

      const amount = Math.max(0, Number(entry.amount) || 0);
      if (amount <= 0) return null;

      const date = /^\d{4}-\d{2}-\d{2}$/.test(String(entry.date || ''))
        ? String(entry.date)
        : todayISO();

      return {
        id: entry.id || uid(),
        goalId: String(entry.goalId || ''),
        goalName: String(entry.goalName || 'Saving goal'),
        day: Math.max(1, Math.floor(Number(entry.day) || 1)),
        amount,
        date,
        createdAt: Math.max(0, Number(entry.createdAt) || Date.now())
      };
    }

    function loadSavingHistory() {
      try {
        const data = JSON.parse(localStorage.getItem(HISTORY_KEY)) || [];
        if (!Array.isArray(data)) return [];
        return data
          .map(normalizeHistoryEntry)
          .filter(Boolean)
          .sort((a, b) => a.createdAt - b.createdAt);
      } catch {
        return [];
      }
    }

    function saveSavingHistory() {
      savingHistory = savingHistory
        .map(normalizeHistoryEntry)
        .filter(Boolean)
        .sort((a, b) => a.createdAt - b.createdAt)
        .slice(-1200);
      localStorage.setItem(HISTORY_KEY, JSON.stringify(savingHistory));
    }

    function recordSavingProgress(goal, day, amount) {
      const dayNumber = Math.max(1, Math.floor(Number(day) || 1));
      const alreadyRecorded = savingHistory.some(item =>
        item.goalId === goal.id && item.day === dayNumber
      );

      if (alreadyRecorded) return false;

      savingHistory.push({
        id: uid(),
        goalId: goal.id,
        goalName: goal.name,
        day: dayNumber,
        amount: Number(amount) || getSavingAmountForDay(goal, dayNumber),
        date: todayISO(),
        createdAt: Date.now() + dayNumber / 1000
      });
      saveSavingHistory();
      return true;
    }

    function removeHistoryForGoal(goalId) {
      const beforeCount = savingHistory.length;
      savingHistory = savingHistory.filter(item => item.goalId !== goalId);
      if (savingHistory.length !== beforeCount) saveSavingHistory();
    }

    function removeHistoryForGoalDay(goalId, day) {
      const beforeCount = savingHistory.length;
      savingHistory = savingHistory.filter(item => !(item.goalId === goalId && item.day === day));
      if (savingHistory.length !== beforeCount) saveSavingHistory();
    }

    function getExistingSaveCount() {
      const savedFromActive = goals.reduce((sum, goal) => sum + goal.doneDays.length, 0);
      const savedFromAchievements = achievements.reduce((sum, achievement) => {
        const daysUsed = Number(achievement.daysUsed || achievement.doneDays?.length || achievement.days || 0);
        return sum + Math.max(0, daysUsed);
      }, 0);
      return Math.max(savingHistory.length, savedFromActive + savedFromAchievements);
    }

    function awardXP(amount) {
      const xpAmount = Math.max(0, Math.floor(Number(amount) || 0));
      if (xpAmount <= 0) return;

      const previousLevel = getLevelFromXP(gameState.xp);
      gameState.xp += xpAmount;
      gameState.level = getLevelFromXP(gameState.xp);

      if (gameState.level > previousLevel) {
        pendingLevelUp = true;
        setTimeout(() => showToast(`Level up! Level ${gameState.level}`), 80);
      }

      saveGameState();
    }

    function updateSavingStreak(saveDate = todayISO()) {
      if (gameState.lastSaveDate === saveDate) return 0;

      if (!gameState.lastSaveDate) {
        gameState.streak = 1;
      } else {
        const previous = dateFromISO(gameState.lastSaveDate);
        const current = dateFromISO(saveDate);
        const dayDifference = Math.round((current - previous) / 86400000);
        gameState.streak = dayDifference === 1 ? gameState.streak + 1 : 1;
      }

      gameState.lastSaveDate = saveDate;
      return gameState.streak > 1 ? XP_STREAK : 0;
    }

    function unlockBadge(id, options = {}) {
      if (gameState.badges.includes(id)) return false;

      const badge = BADGE_DEFS.find(item => item.id === id);
      if (!badge) return false;

      gameState.badges.push(id);
      recentBadgeId = id;
      saveGameState();

      if (!options.silent) {
        setTimeout(() => showToast(`${badge.name} badge unlocked`), 120);
      }

      return true;
    }

    function getAchievementRarity(amount) {
      if (amount >= 20000) return 'legendary';
      if (amount >= 10000) return 'epic';
      if (amount >= 5000) return 'rare';
      return 'common';
    }

    function getRarityLabel(rarity) {
      return rarity === 'legendary' ? 'Legendary' : rarity === 'epic' ? 'Epic' : rarity === 'rare' ? 'Rare' : 'Common';
    }

    function showAchievementPopup(achievement) {
      const popup = document.getElementById('achievementPopup');
      if (!popup || !achievement) return;

      const title = document.getElementById('achievementPopupTitle');
      const rarity = document.getElementById('achievementPopupRarity');
      if (title) title.textContent = achievement.name || 'Unlocked';
      if (rarity) rarity.textContent = getRarityLabel(getAchievementRarity(Number(achievement.totalSaved || achievement.target || 0)));

      popup.dataset.rarity = getAchievementRarity(Number(achievement.totalSaved || achievement.target || 0));
      popup.hidden = false;
      popup.classList.add('is-visible');

      clearTimeout(popup.popupTimer);
      popup.popupTimer = setTimeout(() => {
        popup.classList.remove('is-visible');
        setTimeout(() => { if (popup) popup.hidden = true; }, 260);
      }, 2800);
    }

    function openResetModal() {
      const modal = document.getElementById('resetConfirmModal');
      if (!modal) return;
      modal.style.display = 'flex';
      document.body.style.overflow = 'hidden';
      refreshIcons();
    }

    function closeResetModal() {
      const modal = document.getElementById('resetConfirmModal');
      if (!modal) return;
      modal.style.display = 'none';
      const achievementScreen = document.getElementById('achievementScreen');
      const levelScreen = document.getElementById('levelScreen');
      document.body.style.overflow = (achievementScreen && !achievementScreen.hidden) || (levelScreen && !levelScreen.hidden)
        ? 'hidden'
        : '';
    }

    function confirmResetProgress() {
      gameState = normalizeGameState({ xp: 0, badges: [], streak: 0, totalSaves: 0, lastSaveDate: null });
      achievements = [];
      pendingLevelUp = false;
      recentBadgeId = null;
      saveGameState();
      saveAchievements();
      updateAchievementBadge();
      renderAchievements();
      render();
      updateProfileCard();
      showToast('Progress reset successfully');
      closeResetModal();
    }

    function evaluateBadges(options = {}) {
      if (gameState.totalSaves > 0 || savingHistory.length > 0) {
        unlockBadge('first-save', options);
      }

      if (gameState.streak >= 7) {
        unlockBadge('seven-day-streak', options);
      }

      if (achievements.length > 0 || goals.some(goal => goal.doneDays.length >= goal.days)) {
        unlockBadge('goal-completed', options);
      }

      if (gameState.streak >= 30 || gameState.totalSaves >= 30 || savingHistory.length >= 30) {
        unlockBadge('consistency-master', options);
      }
    }

    function rewardSavingDays(count) {
      const savedCount = Math.max(0, Math.floor(Number(count) || 0));
      if (savedCount <= 0) return;

      gameState.totalSaves += savedCount;
      awardXP(savedCount * XP_SAVE);

      const streakXP = updateSavingStreak(todayISO());
      if (streakXP > 0) awardXP(streakXP);

      evaluateBadges();
      saveGameState();
    }

    function rewardGoalCompletion() {
      awardXP(XP_COMPLETE);
      unlockBadge('goal-completed');
      evaluateBadges();
      saveGameState();
    }

    function bootstrapGameStateFromExistingProgress() {
      const existingSaves = getExistingSaveCount();
      const completedCount = achievements.length;
      const hadStoredGame = Boolean(localStorage.getItem(GAME_KEY));

      if (!hadStoredGame && (existingSaves > 0 || completedCount > 0)) {
        gameState.totalSaves = existingSaves;
        gameState.xp = (existingSaves * XP_SAVE) + (completedCount * XP_COMPLETE);
        gameState.level = getLevelFromXP(gameState.xp);
      } else if (gameState.totalSaves < existingSaves) {
        gameState.totalSaves = existingSaves;
      }

      evaluateBadges({ silent: true });
      saveGameState();
    }

    function checkAndMoveCompleted() {
      const completed = goals.filter(g => g.doneDays && g.doneDays.length >= g.days);
      if (completed.length === 0) return false;

      let moved = false;
      const completedIds = new Set(completed.map(goal => goal.id));
      const newUnlocks = [];
      completed.forEach(goal => {
        if (!achievements.find(a => a.id === goal.id)) {
          const achievement = buildAchievement(goal);
          achievements.push(achievement);
          newUnlocks.push(achievement);
          moved = true;
        }
      });

      goals = goals.filter(goal => !completedIds.has(goal.id));
      saveGoals(goals);

      if (moved) {
        saveAchievements();
        newUnlocks.forEach(showAchievementPopup);
      }

      updateAchievementBadge();
      return moved;
    }

    function updateAchievementBadge() {
      const badge = document.getElementById('achievementBadge');
      if (!badge) return;
      if (achievements.length > 0) {
        badge.textContent = achievements.length;
        badge.setAttribute('aria-label', `${achievements.length} completed ${achievements.length === 1 ? 'goal' : 'goals'}`);
        badge.classList.add('is-visible');
      } else {
        badge.textContent = '';
        badge.setAttribute('aria-label', '0 completed goals');
        badge.classList.remove('is-visible');
      }
    }

    function openAchievements() {
      const screen = document.getElementById('achievementScreen');
      if (!screen) return;
      renderAchievements();
      screen.hidden = false;
      screen.scrollTop = 0;
      requestAnimationFrame(() => screen.classList.add('is-open'));
      document.body.style.overflow = 'hidden';
      refreshIcons();
    }

    function closeAchievementsScreen() {
      const screen = document.getElementById('achievementScreen');
      if (!screen) return;
      screen.classList.remove('is-open');
      setTimeout(() => {
        if (!screen.classList.contains('is-open')) screen.hidden = true;
      }, 300);
      document.body.style.overflow = '';
    }

    function renderAchievements() {
      const list = document.getElementById('achievementList');
      const empty = document.getElementById('achievementEmpty');
      const subtitle = document.getElementById('achievementSubtitle');
      const summaryCount = document.getElementById('achievementSummaryCount');
      const summaryTotal = document.getElementById('achievementSummaryTotal');
      if (!list || !empty || !subtitle) return;

      if (achievements.length === 0) {
        empty.style.display = 'block';
        list.innerHTML = '';
        subtitle.textContent = 'Complete a goal to earn achievements';
        if (summaryCount) summaryCount.textContent = '0';
        if (summaryTotal) summaryTotal.textContent = '฿0';
        return;
      }

      empty.style.display = 'none';
      subtitle.textContent = achievements.length === 1
        ? '1 goal completed'
        : achievements.length + ' goals completed';

      const totalAchieved = achievements.reduce((sum, item) => sum + Number(item.totalSaved || item.target || 0), 0);
      if (summaryCount) summaryCount.textContent = achievements.length;
      if (summaryTotal) summaryTotal.textContent = `฿${fmtCompact(totalAchieved)}`;

      list.innerHTML = achievements.slice().reverse().map((a, idx) => {
        const completedDate = a.completedAt
          ? new Date(a.completedAt).toLocaleDateString('en-US', { year:'numeric', month:'short', day:'numeric' })
          : 'Unknown date';
        const totalFormatted = fmt(a.totalSaved || a.target || 0);
        const daysUsed = a.daysUsed || a.days || 0;
        const amount = Number(a.totalSaved || a.target || 0);
        const rarity = amount >= 20000 ? 'legendary' : amount >= 10000 ? 'epic' : amount >= 5000 ? 'rare' : 'common';
        const rarityLabel = rarity === 'legendary' ? 'Legendary' : rarity === 'epic' ? 'Epic' : rarity === 'rare' ? 'Rare' : 'Common';

        return `<article class="achievement-card" data-achievement-id="${esc(a.id)}" data-rarity="${rarity}" style="animation-delay:${idx * 0.06}s">
          <button class="achievement-delete-btn" data-achievement-id="${esc(a.id)}" type="button" title="Delete achievement" aria-label="Delete achievement">
            <i data-lucide="trash-2"></i>
          </button>
          ${a.image
            ? `<img class="achievement-cover" src="${a.image}" alt="${esc(a.name)} achievement cover" loading="lazy">`
            : `<div class="achievement-medal"><i data-lucide="trophy"></i></div>`
          }
          <div class="achievement-content">
            <div class="achievement-topline">
              <h3 class="achievement-name">${esc(a.name)}</h3>
              <span class="achievement-badge-chip"><i data-lucide="check-circle-2"></i>${rarityLabel}</span>
            </div>
            <div class="achievement-total">฿${totalFormatted}</div>
            <div class="achievement-stats">
              <div class="achievement-stat">
                <div class="achievement-stat-value">฿${totalFormatted}</div>
                <div class="achievement-stat-label">Total saved</div>
              </div>
              <div class="achievement-stat">
                <div class="achievement-stat-value">${daysUsed}d</div>
                <div class="achievement-stat-label">Total days used</div>
              </div>
              <div class="achievement-stat">
                <div class="achievement-stat-value">${completedDate}</div>
                <div class="achievement-stat-label">Completion date</div>
              </div>
            </div>
          </div>
        </article>`;
      }).join('');
    }

    function findAchievementCard(id) {
      return [...document.querySelectorAll('.achievement-card')]
        .find(card => card.dataset.achievementId === id);
    }

    function askDeleteAchievement(id) {
      if (!id || !achievements.some(item => item.id === id)) return;

      achievementDeleteTargetId = id;
      document.getElementById('achievementDeleteModal').style.display = 'flex';
      document.body.style.overflow = 'hidden';
      refreshIcons();
    }

    function closeAchievementDeleteModal() {
      achievementDeleteTargetId = null;
      const modal = document.getElementById('achievementDeleteModal');
      if (modal) modal.style.display = 'none';

      const screen = document.getElementById('achievementScreen');
      document.body.style.overflow = screen && !screen.hidden ? 'hidden' : '';
    }

    function confirmAchievementDelete() {
      if (!achievementDeleteTargetId) return;

      const id = achievementDeleteTargetId;
      const card = findAchievementCard(id);
      closeAchievementDeleteModal();

      if (card) card.classList.add('is-deleting');

      setTimeout(() => {
        const beforeCount = achievements.length;
        achievements = achievements.filter(item => item.id !== id);

        if (achievements.length !== beforeCount) {
          saveAchievements();
          updateAchievementBadge();
          renderAchievements();
          render();
          showToast('Achievement deleted');
        }
      }, card ? 280 : 0);
    }

    function applyTheme(theme) {
      html.setAttribute('data-theme', theme);
      themeBtn.innerHTML = `<i data-lucide="${theme === 'dark' ? 'sun' : 'moon'}"></i>`;
      themeBtn.title = theme === 'dark' ? 'Switch to light theme' : 'Switch to dark theme';
      localStorage.setItem(THEME_KEY, theme);
      refreshIcons();
    }

    const savedTheme = localStorage.getItem(THEME_KEY)
      || (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light');

    applyTheme(savedTheme);

    themeBtn.addEventListener('click', () => {
      applyTheme(html.getAttribute('data-theme') === 'dark' ? 'light' : 'dark');
    });

    const isIos = /iphone|ipad|ipod/i.test(navigator.userAgent);
    const isInStandaloneMode = window.navigator.standalone === true
      || window.matchMedia('(display-mode: standalone)').matches;

    if (isIos && !isInStandaloneMode && !localStorage.getItem('ios_banner_dismissed')) {
      setTimeout(() => {
        iosBanner.style.display = 'flex';
        refreshIcons();
      }, 1200);
    }

    window.addEventListener('beforeinstallprompt', event => {
      event.preventDefault();
      deferredPrompt = event;
      if (!localStorage.getItem('pwa_dismissed')) {
        installBanner.style.display = 'flex';
        refreshIcons();
      }
    });

    installBtn.addEventListener('click', async () => {
      if (!deferredPrompt) return;
      deferredPrompt.prompt();
      const { outcome } = await deferredPrompt.userChoice;
      if (outcome === 'accepted') showToast('My Goals installed');
      deferredPrompt = null;
      installBanner.style.display = 'none';
    });

    dismissBanner.addEventListener('click', () => {
      installBanner.style.display = 'none';
      localStorage.setItem('pwa_dismissed', '1');
    });

    dismissIosBanner.addEventListener('click', () => {
      iosBanner.style.display = 'none';
      localStorage.setItem('ios_banner_dismissed', '1');
    });

    window.addEventListener('appinstalled', () => {
      installBanner.style.display = 'none';
      showToast('App installed successfully');
    });

    const fmt = number => Number(number || 0).toLocaleString('th-TH', {
      minimumFractionDigits: 0,
      maximumFractionDigits: 2
    });

    const fmtCompact = number => {
      const n = Number(number || 0);
      if (n >= 1000000) return `${(n / 1000000).toFixed(1).replace(/\.0$/, '')}m`;
      if (n >= 1000) return `${(n / 1000).toFixed(1).replace(/\.0$/, '')}k`;
      return fmt(n);
    };

    function esc(value) {
      return String(value ?? '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
    }

    function getDailyAmount(goal) {
      return Number(goal.dailyAmount) > 0 ? Number(goal.dailyAmount) : goal.target / goal.days;
    }

    function calcSaved(goal) {
      return Math.min(goal.target, goal.doneDays.length * getDailyAmount(goal));
    }

    function getSavingAmountForDay(goal, day) {
      const daily = getDailyAmount(goal);
      const dayNumber = Math.max(1, Math.floor(Number(day) || 1));
      const previousSaved = Math.min(goal.target, daily * (dayNumber - 1));
      const currentSaved = Math.min(goal.target, daily * dayNumber);
      return Math.max(0, currentSaved - previousSaved) || daily;
    }

    function iconFor(name) {
      const value = String(name).toLowerCase();
      if (/iphone|phone|mobile|samsung/.test(value)) return 'smartphone';
      if (/car|truck/.test(value)) return 'car';
      if (/japan|trip|travel|vacation|tour|flight/.test(value)) return 'plane';
      if (/house|home|condo|apartment/.test(value)) return 'home';
      if (/laptop|computer|mac/.test(value)) return 'laptop';
      if (/watch/.test(value)) return 'watch';
      if (/bike|bicycle|motorbike/.test(value)) return 'bike';
      if (/camera/.test(value)) return 'camera';
      if (/game|ps5|xbox|switch/.test(value)) return 'gamepad-2';
      if (/bag|shopping/.test(value)) return 'shopping-bag';
      return 'target';
    }

    function getCalendarDaysForGoal(goal) {
      return calculateCalendarDaysNeeded(
        goal.days,
        goal.skippedWeekdays || [],
        goal.startDate || todayISO()
      );
    }

    function getCountdownInfo(goal) {
      const isComplete = goal.doneDays.length >= goal.days;
      if (isComplete) {
        return { type: 'done', label: 'Goal completed', daysLeft: 0, endDate: null };
      }

      if (goal.startDate) {
        const calendarDays = getCalendarDaysForGoal(goal);
        if (!Number.isFinite(calendarDays)) {
          return { type: 'overdue', label: 'No saving days', daysLeft: 0, endDate: null };
        }

        const start = dateFromISO(goal.startDate);
        const endDate = addDays(start, Math.max(0, calendarDays - 1));
        const today = dateFromISO(todayISO());
        const inclusiveDaysLeft = Math.floor((endDate - today) / 86400000) + 1;

        if (inclusiveDaysLeft <= 0) {
          return {
            type: 'overdue',
            label: `${Math.abs(inclusiveDaysLeft) + 1}d overdue`,
            daysLeft: inclusiveDaysLeft,
            endDate
          };
        }

        const type = inclusiveDaysLeft <= Math.ceil(calendarDays * 0.1) ? 'urgent' : 'ok';
        return { type, label: `${inclusiveDaysLeft}d left`, daysLeft: inclusiveDaysLeft, endDate };
      }

      const daysLeft = goal.days - goal.doneDays.length;
      return { type: 'ok', label: `${daysLeft} saving days left`, daysLeft, endDate: null };
    }

    function getAdvancedStats(goal) {
      const daily = getDailyAmount(goal);
      const saved = calcSaved(goal);
      const remaining = Math.max(0, goal.target - saved);
      const doneDays = goal.doneDays.length;
      const avgSavedPerDay = doneDays > 0 ? saved / doneDays : 0;
      const pct = Math.min(100, Math.round((saved / goal.target) * 100));
      const calendarDays = getCalendarDaysForGoal(goal);

      let estDate = '-';
      if (remaining > 0 && doneDays > 0) {
        const savingDaysNeeded = Math.ceil(remaining / daily);
        const calendarDaysNeeded = calculateCalendarDaysNeeded(
          savingDaysNeeded,
          goal.skippedWeekdays || [],
          todayISO()
        );

        if (Number.isFinite(calendarDaysNeeded)) {
          const estimated = addDays(dateFromISO(todayISO()), Math.max(0, calendarDaysNeeded - 1));
          estDate = estimated.toLocaleDateString('en-GB', { day: 'numeric', month: 'short' });
        }
      } else if (doneDays >= goal.days) {
        estDate = 'Done';
      }

      return { saved, remaining, daily, doneDays, avgSavedPerDay, pct, estDate, calendarDays };
    }

    function getPaceInfo(goal) {
      if (goal.doneDays.length >= goal.days) {
        return { type: 'good', label: 'Finished', icon: 'check-circle' };
      }

      if (!goal.startDate) {
        return goal.doneDays.length > 0
          ? { type: 'good', label: 'Active', icon: 'activity' }
          : { type: 'idle', label: 'Not started', icon: 'pause-circle' };
      }

      const skipped = new Set(goal.skippedWeekdays || []);
      const start = dateFromISO(goal.startDate);
      const today = dateFromISO(todayISO());
      let expectedSavingDays = 0;
      const cursor = new Date(start);

      while (cursor <= today && expectedSavingDays < goal.days) {
        if (!skipped.has(cursor.getDay())) expectedSavingDays++;
        cursor.setDate(cursor.getDate() + 1);
      }

      if (expectedSavingDays <= 0) {
        return { type: 'idle', label: 'Upcoming', icon: 'calendar' };
      }

      if (goal.doneDays.length >= expectedSavingDays) {
        return { type: 'good', label: 'On track', icon: 'activity' };
      }

      return { type: 'behind', label: 'Behind', icon: 'alert-triangle' };
    }

    function statusIcon(type) {
      if (type === 'done') return 'trophy';
      if (type === 'overdue') return 'alert-triangle';
      if (type === 'urgent') return 'clock';
      return 'calendar';
    }

    function skippedWeekdayLabel(skippedWeekdays) {
      const skipped = normalizeSkippedWeekdays(skippedWeekdays);
      if (!skipped.length) return 'No skipped weekdays';
      return `Skips ${skipped.map(day => WEEKDAY_SHORT[day]).join(', ')}`;
    }

    function durationLabel(days) {
      if (!Number.isFinite(days)) return 'Unavailable';
      return `${days} calendar ${days === 1 ? 'day' : 'days'}`;
    }

    function showToast(message) {
      const toast = document.getElementById('toast');
      toast.textContent = message;
      toast.classList.add('show');
      clearTimeout(toastTimer);
      toastTimer = setTimeout(() => toast.classList.remove('show'), 2600);
    }

    function addRipple(button, event) {
      const ripple = document.createElement('span');
      ripple.className = 'ripple';

      const rect = button.getBoundingClientRect();
      const size = Math.max(rect.width, rect.height);
      ripple.style.width = `${size}px`;
      ripple.style.height = `${size}px`;
      ripple.style.left = `${event.clientX - rect.left - size / 2}px`;
      ripple.style.top = `${event.clientY - rect.top - size / 2}px`;

      button.appendChild(ripple);
      ripple.addEventListener('animationend', () => ripple.remove());
    }

    function hasAppActivity() {
      return goals.length > 0
        || achievements.length > 0
        || savingHistory.length > 0
        || gameState.xp > 0
        || gameState.badges.length > 0;
    }

    function updateProfileCard() {
      const level = getLevelFromXP(gameState.xp);
      const xpIntoLevel = gameState.xp % 100;
      const levelEl = document.getElementById('levelValue');
      const xpEl = document.getElementById('levelXP');
      const fill = document.getElementById('levelXPFill');
      const caption = document.getElementById('levelCaption');
      const badgeGrid = document.getElementById('levelBadgeGrid');

      if (levelEl) levelEl.textContent = level;
      if (xpEl) xpEl.textContent = `${gameState.xp} XP`;
      if (fill) fill.style.setProperty('--value', `${xpIntoLevel}%`);
      const progressPercent = document.getElementById('levelProgressPercent');
      if (progressPercent) progressPercent.textContent = `${xpIntoLevel}%`;
      if (caption) {
        const streakText = gameState.streak > 0
          ? ` · ${gameState.streak}-day streak`
          : ' · start a streak today';
        caption.textContent = `${xpIntoLevel} / 100 XP to next level${streakText}`;
      }

      if (badgeGrid) {
        badgeGrid.innerHTML = BADGE_DEFS.map(badge => {
          const earned = gameState.badges.includes(badge.id);
          const isNew = recentBadgeId === badge.id;
          const badgeTitle = earned ? badge.name : `${badge.name} locked`;
          return `
            <div class="level-badge-chip ${earned ? 'is-earned' : 'is-locked'}${isNew ? ' is-new' : ''}" title="${badgeTitle}">
              <span class="badge-icon"><i data-lucide="${earned ? badge.icon : 'lock'}"></i></span>
              <span>${badge.name}</span>
            </div>
          `;
        }).join('');
      }

      if (pendingLevelUp && levelEl) {
        levelEl.classList.remove('level-up');
        void levelEl.offsetWidth;
        levelEl.classList.add('level-up');
        levelEl.addEventListener('animationend', () => levelEl.classList.remove('level-up'), { once: true });
        pendingLevelUp = false;
      }

      if (recentBadgeId) {
        setTimeout(() => {
          recentBadgeId = null;
        }, 600);
      }
    }

    function openLevelScreen() {
      const screen = document.getElementById('levelScreen');
      if (!screen) return;
      updateProfileCard();
      screen.hidden = false;
      requestAnimationFrame(() => screen.classList.add('is-open'));
      document.body.style.overflow = 'hidden';
      refreshIcons();
    }

    function closeLevelScreen() {
      const screen = document.getElementById('levelScreen');
      if (!screen) return;
      screen.classList.remove('is-open');
      screen.addEventListener('transitionend', () => {
        if (screen && !screen.classList.contains('is-open')) screen.hidden = true;
      }, { once: true });
      document.body.style.overflow = '';
    }

    function deriveProgressEventsFromGoal(goal) {
      const rawDoneDays = Array.isArray(goal.doneDays) && goal.doneDays.length
        ? goal.doneDays
        : Array.from({ length: Math.max(0, Number(goal.daysUsed) || 0) }, (_, index) => index + 1);

      const doneDays = [...new Set(rawDoneDays.map(Number).filter(day => day > 0))]
        .sort((a, b) => a - b);

      if (!doneDays.length) return [];

      const totalSaved = Math.max(0, Number(goal.totalSaved) || calcSaved(goal) || goal.target || 0);
      const start = dateFromISO(goal.startDate || todayISO());
      const fallbackStart = addDays(dateFromISO(todayISO()), -Math.max(0, doneDays.length - 1));

      return doneDays.map((day, index) => {
        const previousSaved = goal.completed ? (totalSaved / doneDays.length) * index : 0;
        const currentSaved = goal.completed ? (totalSaved / doneDays.length) * (index + 1) : 0;
        const amount = goal.completed
          ? Math.max(0, currentSaved - previousSaved)
          : getSavingAmountForDay(goal, day);
        const eventDate = goal.startDate
          ? addDays(start, Math.max(0, day - 1))
          : addDays(fallbackStart, index);

        return {
          id: `${goal.id || 'goal'}_${day}`,
          goalId: goal.id || '',
          goalName: goal.name || 'Saving goal',
          day,
          amount,
          date: toISODate(eventDate),
          createdAt: dateFromISO(toISODate(eventDate)).getTime() + index
        };
      }).filter(entry => entry.amount > 0);
    }

    function getSelectedSkippedWeekdays() {
      return [...document.querySelectorAll('.skip-day:checked')].map(input => Number(input.value));
    }

    function setSelectedSkippedWeekdays(skippedWeekdays) {
      const skipped = new Set(normalizeSkippedWeekdays(skippedWeekdays));
      document.querySelectorAll('.skip-day').forEach(input => {
        input.checked = skipped.has(Number(input.value));
      });
    }

    function setCalcMode(mode) {
      calcMode = mode === 'byDaily' ? 'byDaily' : 'byDays';
      const form = document.getElementById('goalForm');
      const daysInput = document.getElementById('fDays');
      const dailyInput = document.getElementById('fDaily');

      form.dataset.calcMode = calcMode;
      daysInput.disabled = calcMode === 'byDaily';
      daysInput.required = calcMode === 'byDays';
      dailyInput.disabled = calcMode === 'byDays';
      dailyInput.required = calcMode === 'byDaily';

      document.querySelectorAll('.mode-tab').forEach(button => {
        const active = button.dataset.mode === calcMode;
        button.classList.toggle('active', active);
        button.setAttribute('aria-selected', active ? 'true' : 'false');
      });

      updateCalculator();
    }

    function getFormCalculation() {
      const total = parseFloat(document.getElementById('fTarget').value);
      const daysInput = parseInt(document.getElementById('fDays').value, 10);
      const dailyInput = parseFloat(document.getElementById('fDaily').value);
      const skippedWeekdays = getSelectedSkippedWeekdays();
      const startDate = document.getElementById('fStart').value || todayISO();

      let requiredSavingDays = 0;
      let dailyAmount = 0;
      let reason = '';

      if (!Number.isFinite(total) || total <= 0) {
        reason = 'Enter a total amount.';
      } else if (calcMode === 'byDays') {
        if (!Number.isFinite(daysInput) || daysInput <= 0) {
          reason = 'Enter the number of saving days.';
        } else {
          requiredSavingDays = daysInput;
          dailyAmount = total / requiredSavingDays;
        }
      } else {
        if (!Number.isFinite(dailyInput) || dailyInput <= 0) {
          reason = 'Enter a daily saving amount.';
        } else {
          dailyAmount = dailyInput;
          requiredSavingDays = Math.ceil(total / dailyAmount);
        }
      }

      if (!reason && requiredSavingDays > MAX_SAVING_DAYS) {
        reason = `Use ${MAX_SAVING_DAYS} saving days or fewer.`;
      }

      if (!reason && skippedWeekdays.length >= 7) {
        reason = 'Leave at least one weekday available for saving.';
      }

      const calendarDays = reason
        ? 0
        : calculateCalendarDaysNeeded(requiredSavingDays, skippedWeekdays, startDate);

      if (!reason && !Number.isFinite(calendarDays)) {
        reason = 'Calendar duration cannot be calculated.';
      }

      return {
        valid: !reason,
        reason,
        total,
        dailyAmount,
        requiredSavingDays,
        calendarDays,
        skippedWeekdays,
        startDate
      };
    }

    function updateCalculator() {
      const result = getFormCalculation();
      const resultCard = document.getElementById('calcResultCard');
      const resultLabel = document.getElementById('calcResultLabel');
      const resultValue = document.getElementById('calcResultValue');
      const resultSubline = document.getElementById('calcResultSubline');
      const calendarResult = document.getElementById('calendarResult');
      const calcWarning = document.getElementById('calcWarning');
      const saveBtn = document.getElementById('saveBtn');
      const skipSummary = document.getElementById('skipSummary');

      skipSummary.textContent = result.skippedWeekdays.length
        ? `${result.skippedWeekdays.length} skipped`
        : 'No skips';

      resultCard.classList.toggle('invalid', !result.valid);
      saveBtn.disabled = !result.valid;

      if (calcMode === 'byDays') {
        resultLabel.textContent = 'Daily saving';
        resultValue.textContent = result.valid ? `฿${fmt(result.dailyAmount)}` : '-';
        resultSubline.textContent = result.valid
          ? `${result.requiredSavingDays} saving ${result.requiredSavingDays === 1 ? 'day' : 'days'}`
          : 'Enter total amount and days.';
      } else {
        resultLabel.textContent = 'Required saving days';
        resultValue.textContent = result.valid ? `${result.requiredSavingDays}d` : '-';
        resultSubline.textContent = result.valid
          ? `At ฿${fmt(result.dailyAmount)} per saving day`
          : 'Enter total amount and daily saving.';
      }

      calendarResult.textContent = result.valid
        ? `Calendar duration: ${durationLabel(result.calendarDays)} after skipped weekdays`
        : 'Calendar duration: -';

      calcWarning.textContent = result.reason || '';
    }

    function render() {
      const list = document.getElementById('goalsList');
      const empty = document.getElementById('emptyState');
      const hero = document.getElementById('heroCard');
      const sectionLabel = document.getElementById('sectionLabel');

      list.innerHTML = '';
      updateProfileCard();

      if (!goals.length) {
        empty.style.display = 'block';
        hero.style.display = 'none';
        sectionLabel.style.display = 'none';
        refreshIcons();
        return;
      }

      empty.style.display = 'none';
      hero.style.display = 'block';
      sectionLabel.style.display = 'flex';

      let totalSaved = 0;
      let totalTarget = 0;
      let complete = 0;

      goals.forEach(goal => {
        totalSaved += calcSaved(goal);
        totalTarget += goal.target;
        if (goal.doneDays.length >= goal.days) complete++;
      });

      const overallPct = totalTarget > 0 ? Math.min(100, Math.round((totalSaved / totalTarget) * 100)) : 0;

      document.getElementById('heroAmount').textContent = fmt(totalSaved);
      document.getElementById('heroGoalText').textContent = `Across ${goals.length} active ${goals.length === 1 ? 'goal' : 'goals'}`;
      document.getElementById('heroProgress').style.setProperty('--value', `${overallPct}%`);
      document.getElementById('hGoals').textContent = goals.length;
      document.getElementById('hTarget').textContent = `฿${fmtCompact(totalTarget)}`;
      document.getElementById('hDone').textContent = complete;

      goals.forEach((goal, index) => {
        const stats = getAdvancedStats(goal);
        const countdown = getCountdownInfo(goal);
        const pace = getPaceInfo(goal);
        const isComplete = goal.doneDays.length >= goal.days;
        const { saved, remaining, daily, doneDays, avgSavedPerDay, pct, estDate, calendarDays } = stats;

        let gridHTML = '';
        for (let day = 1; day <= goal.days; day++) {
          const done = goal.doneDays.includes(day);
          gridHTML += `
            <button class="day-btn${done ? ' done' : ''}" onclick="toggleDay('${goal.id}', ${day}, this)" type="button" aria-label="Saving day ${day}">
              ${day}
            </button>
          `;
        }

        let milestonesHTML = '<div class="milestone-track">';
        [25, 50, 75, 100].forEach(milestone => {
          milestonesHTML += `
            <div class="milestone-dot${pct >= milestone ? ' reached' : ''}" style="left:${milestone}%">
              <div class="milestone-dot-label">${milestone}%</div>
            </div>
          `;
        });
        milestonesHTML += '</div>';

        const dueDateHTML = countdown.endDate
          ? `<span class="soft-meta">Due ${countdown.endDate.toLocaleDateString('en-GB', { day: 'numeric', month: 'short' })}</span>`
          : '';

        const card = document.createElement('article');
        card.className = `goal-card card-enter${isComplete ? ' is-complete' : ''}`;
        card.id = `card_${goal.id}`;
        card.style.animationDelay = `${index * 0.06}s`;

        card.innerHTML = `
          ${isComplete ? `
            <div class="complete-bar">
              <i data-lucide="trophy"></i>
              Goal achieved. Congratulations.
            </div>
          ` : ''}

          ${goal.image
            ? `<img class="card-cover" src="${goal.image}" alt="${esc(goal.name)}" loading="lazy" />`
            : `<div class="card-cover-placeholder"><i data-lucide="${iconFor(goal.name)}"></i></div>`
          }

          <div class="card-body">
            <div class="card-header">
              <div>
                <div class="card-name">${esc(goal.name)}</div>
                <div class="card-daily">
                  ฿<strong>${fmt(daily)}</strong>/saving day · ${goal.days} saving days<br />
                  ${durationLabel(calendarDays)} · ${skippedWeekdayLabel(goal.skippedWeekdays)}
                </div>
              </div>

              <div class="card-actions">
                <button class="card-action-btn" onclick="openEdit('${goal.id}')" type="button" title="Edit" aria-label="Edit">
                  <i data-lucide="edit-3"></i>
                </button>
                <button class="card-action-btn del" onclick="askDelete('${goal.id}')" type="button" title="Delete" aria-label="Delete">
                  <i data-lucide="trash-2"></i>
                </button>
              </div>
            </div>

            <div class="countdown-row">
              <span class="status-badge ${countdown.type}">
                <i data-lucide="${statusIcon(countdown.type)}"></i>
                ${countdown.label}
              </span>
              <span class="pace-badge ${pace.type}">
                <i data-lucide="${pace.icon}"></i>
                ${pace.label}
              </span>
              ${dueDateHTML}
            </div>

            <div class="progress-section">
              <div class="progress-info">
                <span class="progress-saved">฿${fmt(saved)}</span>
                <span class="progress-meta">
                  <span class="progress-pct">${pct}%</span><br />
                  ฿${fmtCompact(remaining)} left
                </span>
              </div>
              <div class="progress-track">
                <div class="progress-fill${isComplete ? ' complete' : countdown.type === 'overdue' ? ' overdue' : ''}" style="--value:${pct}%"></div>
              </div>
              ${milestonesHTML}
            </div>

            <div class="stats-grid">
              <div class="stat-pill">
                <div class="stat-label">Saved</div>
                <div class="stat-value green">฿${fmtCompact(saved)}</div>
              </div>
              <div class="stat-pill">
                <div class="stat-label">Remaining</div>
                <div class="stat-value ${remaining > 0 ? 'blue' : 'green'}">฿${fmtCompact(remaining)}</div>
              </div>
              <div class="stat-pill">
                <div class="stat-label">Calendar</div>
                <div class="stat-value blue">${Number.isFinite(calendarDays) ? `${calendarDays}d` : '-'}</div>
              </div>
              <div class="stat-pill">
                <div class="stat-label">Est. Done</div>
                <div class="stat-value ${avgSavedPerDay >= daily ? 'green' : doneDays > 0 ? 'amber' : 'blue'}">${estDate}</div>
              </div>
            </div>

            <button class="track-toggle" onclick="toggleAccordion('${goal.id}')" id="accBtn_${goal.id}" type="button">
              <span class="track-left">
                <i data-lucide="calendar-days"></i>
                Track saving days
              </span>
              <span class="track-meta">
                ${doneDays}/${goal.days}
                <i class="chevron" id="accChev_${goal.id}" data-lucide="chevron-down"></i>
              </span>
            </button>
          </div>

          <div class="accordion-body" id="acc_${goal.id}">
            <div class="day-panel">
              <div class="day-grid">${gridHTML}</div>
              <div class="day-actions">
                <button class="btn btn-success" onclick="markAll('${goal.id}')" type="button" style="flex:1">
                  <i data-lucide="check-check"></i>
                  Mark all
                </button>
                <button class="btn btn-dim" onclick="clearAll('${goal.id}')" type="button" style="flex:1">
                  <i data-lucide="refresh-cw"></i>
                  Reset
                </button>
              </div>
            </div>
          </div>
        `;

        list.appendChild(card);
      });

      refreshIcons();
    }

    function toggleAccordion(id) {
      const body = document.getElementById(`acc_${id}`);
      const chev = document.getElementById(`accChev_${id}`);
      if (!body) return;

      const open = body.classList.toggle('open');
      if (chev) chev.classList.toggle('open', open);
    }

    function reopenAccordion(id) {
      setTimeout(() => {
        const body = document.getElementById(`acc_${id}`);
        const chev = document.getElementById(`accChev_${id}`);
        if (body) body.classList.add('open');
        if (chev) chev.classList.add('open');
      }, 20);
    }

    function toggleDay(goalId, day, button) {
      const goal = goals.find(item => item.id === goalId);
      if (!goal) return;

      const wasComplete = goal.doneDays.length >= goal.days;
      const index = goal.doneDays.indexOf(day);

      if (index === -1) {
        goal.doneDays.push(day);
        goal.doneDays.sort((a, b) => a - b);
        if (recordSavingProgress(goal, day, getSavingAmountForDay(goal, day))) {
          rewardSavingDays(1);
        }
        if (button) {
          button.classList.add('done', 'just-tapped');
          button.addEventListener('animationend', () => button.classList.remove('just-tapped'), { once: true });
        }
        showToast(`Saving day ${day} completed`);
      } else {
        goal.doneDays.splice(index, 1);
        removeHistoryForGoalDay(goal.id, day);
        showToast(`Saving day ${day} cleared`);
      }

      const nowComplete = goal.doneDays.length >= goal.days;
      if (!wasComplete && nowComplete) {
        goal.completedAt = new Date().toISOString();
        rewardGoalCompletion();
      }

      saveGoals(goals);
      render();
      reopenAccordion(goalId);

      if (!wasComplete && nowComplete) {
        celebrateGoalCompletion(goalId);
        showToast('🏆 Goal completed! Check your Achievements!');
        setTimeout(() => {
          checkAndMoveCompleted();
          render();
        }, 1400);
      }
    }

    function markAll(goalId) {
      const goal = goals.find(item => item.id === goalId);
      if (!goal) return;

      const wasComplete = goal.doneDays.length >= goal.days;
      const completedDays = new Set(goal.doneDays);
      const newDays = Array.from({ length: goal.days }, (_, index) => index + 1)
        .filter(day => !completedDays.has(day));

      goal.doneDays = Array.from({ length: goal.days }, (_, index) => index + 1);

      let recordedCount = 0;
      newDays.forEach(day => {
        if (recordSavingProgress(goal, day, getSavingAmountForDay(goal, day))) {
          recordedCount++;
        }
      });
      rewardSavingDays(recordedCount);

      if (!wasComplete) {
        goal.completedAt = new Date().toISOString();
        rewardGoalCompletion();
      }

      saveGoals(goals);
      render();
      reopenAccordion(goalId);

      if (!wasComplete) {
        celebrateGoalCompletion(goalId);
        showToast('🏆 Goal completed! Check your Achievements!');
        setTimeout(() => {
          checkAndMoveCompleted();
          render();
        }, 1400);
      }
    }

    function clearAll(goalId) {
      const goal = goals.find(item => item.id === goalId);
      if (!goal) return;

      goal.doneDays = [];
      removeHistoryForGoal(goal.id);
      saveGoals(goals);
      render();
      reopenAccordion(goalId);
      showToast('Progress reset');
    }

    function openAdd() {
      currentImgData = null;
      document.getElementById('editId').value = '';
      document.getElementById('goalForm').reset();
      document.getElementById('fStart').value = todayISO();
      document.getElementById('imgPreview').style.display = 'none';
      document.getElementById('removeImg').style.display = 'none';
      document.getElementById('uploadZone').style.display = 'flex';
      document.getElementById('modalTitle').textContent = 'New Goal';
      document.getElementById('saveBtn').innerHTML = '<i data-lucide="check"></i>Save Goal';
      setSelectedSkippedWeekdays([]);
      setCalcMode('byDays');
      document.getElementById('addModal').style.display = 'flex';
      document.body.style.overflow = 'hidden';
      refreshIcons();

      setTimeout(() => document.getElementById('fName').focus(), 180);
    }

    function openEdit(goalId) {
      const goal = goals.find(item => item.id === goalId);
      if (!goal) return;

      currentImgData = goal.image || null;
      document.getElementById('editId').value = goal.id;
      document.getElementById('fName').value = goal.name;
      document.getElementById('fTarget').value = goal.target;
      document.getElementById('fDays').value = goal.days;
      document.getElementById('fDaily').value = getDailyAmount(goal);
      document.getElementById('fStart').value = goal.startDate || todayISO();
      setSelectedSkippedWeekdays(goal.skippedWeekdays || []);

      if (goal.image) {
        document.getElementById('imgPreview').src = goal.image;
        document.getElementById('imgPreview').style.display = 'block';
        document.getElementById('removeImg').style.display = 'inline-flex';
        document.getElementById('uploadZone').style.display = 'none';
      } else {
        document.getElementById('imgPreview').style.display = 'none';
        document.getElementById('removeImg').style.display = 'none';
        document.getElementById('uploadZone').style.display = 'flex';
      }

      document.getElementById('modalTitle').textContent = 'Edit Goal';
      document.getElementById('saveBtn').innerHTML = '<i data-lucide="check"></i>Update Goal';
      setCalcMode(goal.calcMode || 'byDays');
      document.getElementById('addModal').style.display = 'flex';
      document.body.style.overflow = 'hidden';
      refreshIcons();
    }

    function closeAddModal() {
      document.getElementById('addModal').style.display = 'none';
      document.body.style.overflow = '';
    }

    document.getElementById('fImage').addEventListener('change', function () {
      const file = this.files[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = event => {
        currentImgData = event.target.result;
        document.getElementById('imgPreview').src = currentImgData;
        document.getElementById('imgPreview').style.display = 'block';
        document.getElementById('removeImg').style.display = 'inline-flex';
        document.getElementById('uploadZone').style.display = 'none';
        refreshIcons();
      };
      reader.readAsDataURL(file);
    });

    document.getElementById('removeImg').addEventListener('click', () => {
      currentImgData = null;
      document.getElementById('imgPreview').style.display = 'none';
      document.getElementById('removeImg').style.display = 'none';
      document.getElementById('uploadZone').style.display = 'flex';
      document.getElementById('fImage').value = '';
    });

    document.querySelectorAll('.mode-tab').forEach(button => {
      button.addEventListener('click', () => setCalcMode(button.dataset.mode));
    });

    ['fTarget', 'fDays', 'fDaily', 'fStart'].forEach(id => {
      document.getElementById(id).addEventListener('input', updateCalculator);
      document.getElementById(id).addEventListener('change', updateCalculator);
    });

    document.querySelectorAll('.skip-day').forEach(input => {
      input.addEventListener('change', updateCalculator);
    });

    document.getElementById('goalForm').addEventListener('submit', event => {
      event.preventDefault();

      const name = document.getElementById('fName').value.trim();
      const editId = document.getElementById('editId').value;
      const result = getFormCalculation();

      if (!name || !result.valid) {
        updateCalculator();
        return;
      }

      if (editId) {
        const goal = goals.find(item => item.id === editId);
        if (goal) {
          goal.name = name;
          goal.target = result.total;
          goal.days = result.requiredSavingDays;
          goal.dailyAmount = result.dailyAmount;
          goal.calcMode = calcMode;
          goal.skippedWeekdays = result.skippedWeekdays;
          goal.image = currentImgData;
          goal.startDate = result.startDate;
          goal.doneDays = goal.doneDays.filter(day => day <= result.requiredSavingDays);
          savingHistory = savingHistory.filter(item => item.goalId !== goal.id || item.day <= result.requiredSavingDays);
          saveSavingHistory();
        }
        showToast('Goal updated');
      } else {
        goals.push({
          id: uid(),
          name,
          target: result.total,
          days: result.requiredSavingDays,
          dailyAmount: result.dailyAmount,
          calcMode,
          skippedWeekdays: result.skippedWeekdays,
          image: currentImgData,
          startDate: result.startDate,
          doneDays: [],
          createdAt: Date.now()
        });
        showToast('New goal created');
      }

      goals = goals.map(normalizeGoal);
      saveGoals(goals);
      render();
      closeAddModal();
    });

    function askDelete(goalId) {
      deleteTargetId = goalId;
      document.getElementById('confirmModal').style.display = 'flex';
      document.body.style.overflow = 'hidden';
      refreshIcons();
    }

    function closeConfirmModal() {
      deleteTargetId = null;
      document.getElementById('confirmModal').style.display = 'none';
      document.body.style.overflow = '';
    }

    document.getElementById('confirmDelete').addEventListener('click', () => {
      if (!deleteTargetId) return;

      const id = deleteTargetId;
      const card = document.getElementById(`card_${id}`);
      closeConfirmModal();

      if (card) card.classList.add('is-deleting');

      setTimeout(() => {
        goals = goals.filter(goal => goal.id !== id);
        removeHistoryForGoal(id);
        saveGoals(goals);
        render();
        showToast('Goal deleted');
      }, card ? 280 : 0);
    });

    document.getElementById('confirmCancel').addEventListener('click', closeConfirmModal);
    document.getElementById('confirmCancelTop').addEventListener('click', closeConfirmModal);

    document.getElementById('openAddModal').addEventListener('click', function (event) {
      addRipple(this, event);
      openAdd();
    });

    document.getElementById('closeAddModal').addEventListener('click', closeAddModal);
    document.getElementById('cancelBtn').addEventListener('click', closeAddModal);

    document.getElementById('addModal').addEventListener('click', function (event) {
      if (event.target === this) closeAddModal();
    });

    document.getElementById('confirmModal').addEventListener('click', function (event) {
      if (event.target === this) closeConfirmModal();
    });

    document.addEventListener('keydown', event => {
      if (event.key !== 'Escape') return;

      const achievementDeleteModal = document.getElementById('achievementDeleteModal');
      if (achievementDeleteModal && achievementDeleteModal.style.display === 'flex') {
        closeAchievementDeleteModal();
        return;
      }

      if (document.getElementById('addModal').style.display === 'flex') closeAddModal();
      if (document.getElementById('confirmModal').style.display === 'flex') closeConfirmModal();
    });

    function celebrateGoalCompletion(goalId) {
      const card = document.getElementById(`card_${goalId}`);
      const achievementBtn = document.getElementById('achievementBtn');

      // Removed broken card animation classes that were causing text glitches
      // if (card) {
      //   card.classList.add('completion-celebrate');
      //   setTimeout(() => card.classList.add('achievement-exit'), 900);
      // }

      if (achievementBtn) {
        achievementBtn.classList.add('badge-pop');
        achievementBtn.addEventListener('animationend', () => {
          achievementBtn.classList.remove('badge-pop');
        }, { once: true });
      }

      launchConfetti();
    }

    function launchConfetti() {
      const colors = ['#2563eb', '#7c3aed', '#06b6d4', '#16a34a', '#f59e0b', '#ef4444'];

      for (let index = 0; index < 48; index++) {
        const piece = document.createElement('div');
        piece.className = 'confetti-piece';
        piece.style.left = `${Math.random() * 100}vw`;
        piece.style.background = colors[Math.floor(Math.random() * colors.length)];
        piece.style.width = `${Math.random() * 7 + 4}px`;
        piece.style.height = `${Math.random() * 12 + 6}px`;
        piece.style.borderRadius = Math.random() > 0.5 ? '999px' : '3px';
        piece.style.animationDuration = `${Math.random() * 1.6 + 1.4}s`;
        piece.style.animationDelay = `${Math.random() * 0.45}s`;

        document.body.appendChild(piece);
        piece.addEventListener('animationend', () => piece.remove());
      }
    }

    function playPressMotion(target) {
      if (!target || target.disabled) return;
      target.classList.remove('press-bounce');
      void target.offsetWidth;
      target.classList.add('press-bounce');
      target.addEventListener('animationend', () => {
        target.classList.remove('press-bounce');
      }, { once: true });
    }

    window.addEventListener('DOMContentLoaded', () => {
      const achievementBtn = document.getElementById('achievementBtn');
      if (achievementBtn) {
        achievementBtn.addEventListener('click', event => {
          addRipple(achievementBtn, event);
          openAchievements();
        });
      }

      const levelBtn = document.getElementById('levelBtn');
      if (levelBtn) {
        levelBtn.addEventListener('click', event => {
          addRipple(levelBtn, event);
          openLevelScreen();
        });
      }

      const resetBtn = document.getElementById('resetBtn');
      if (resetBtn) {
        resetBtn.addEventListener('click', event => {
          addRipple(resetBtn, event);
          openResetModal();
        });
      }

      // Init achievements and UI state once the DOM is ready.
      checkAndMoveCompleted();
      bootstrapGameStateFromExistingProgress();
      updateAchievementBadge();
      render();
      updateCalculator();
      refreshIcons();
    });

    document.addEventListener('click', event => {
      playPressMotion(event.target.closest('button'));

      const achievementDeleteBtn = event.target.closest('.achievement-delete-btn');
      if (achievementDeleteBtn) {
        askDeleteAchievement(achievementDeleteBtn.dataset.achievementId);
        return;
      }

      if (event.target.closest('#achievementDeleteConfirm')) {
        confirmAchievementDelete();
        return;
      }

      if (event.target.closest('#achievementDeleteCancel') || event.target.closest('#achievementDeleteCancelTop')) {
        closeAchievementDeleteModal();
        return;
      }

      if (event.target.closest('#resetConfirm')) {
        confirmResetProgress();
        return;
      }

      if (event.target.closest('#resetCancel') || event.target.closest('#resetCancelTop')) {
        closeResetModal();
        return;
      }

      if (event.target.id === 'achievementDeleteModal') {
        closeAchievementDeleteModal();
        return;
      }

      if (event.target.id === 'resetConfirmModal') {
        closeResetModal();
        return;
      }

      if (event.target.closest('#closeAchievements')) {
        closeAchievementsScreen();
        return;
      }

      if (event.target.closest('#closeLevel')) {
        closeLevelScreen();
        return;
      }

      if (event.target.id === 'levelScreen') {
        closeLevelScreen();
        return;
      }
    });

    document.addEventListener('keydown', event => {
      const achievementScreen = document.getElementById('achievementScreen');
      const levelScreen = document.getElementById('levelScreen');
      const resetModal = document.getElementById('resetConfirmModal');
      if (event.key === 'Escape') {
        if (resetModal && resetModal.style.display === 'flex') {
          closeResetModal();
          return;
        }
        if (levelScreen && !levelScreen.hidden) {
          closeLevelScreen();
          return;
        }
        if (achievementScreen && !achievementScreen.hidden) {
          closeAchievementsScreen();
        }
      }
    });

    // Init achievements
    checkAndMoveCompleted();
    bootstrapGameStateFromExistingProgress();
    updateAchievementBadge();

    render();
    updateCalculator();
    refreshIcons();
